/*
 * fabs() test harness — prints (input_hex, output_hex) pairs.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

#ifdef EN_PERF
static volatile double g_acc;

static void emit(double x)
{
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += fabs(vx);
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#else
static void emit(double x)
{
    double r = fabs(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf */
    emit_u(0xfff0000000000000ULL);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal: -2^-1074 */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max positive subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                  /* smallest positive normal: 2^-1022 */
    emit(-DBL_MIN);
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit(DBL_MAX);                  /* largest finite: 0x7fefffffffffffff */
    emit(-DBL_MAX);
    emit_u(0x7fefffffffffffffULL);  /* one ULP below DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3fefffffffff0000ULL);  /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000010000ULL);  /* a few ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (8) --- */
    emit(0.5);                      /* 0x3fe0000000000000 */
    emit(-0.5);
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x3fdfffffffffffffULL);  /* one ULP below 0.5 */
    emit(2.0);                      /* 0x4000000000000000 */
    emit(-2.0);
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */

    /* --- Section 6: Mathematically interesting constants (12) --- */
    emit(3.14159265358979323846);   /* pi */
    emit(-3.14159265358979323846);
    emit(1.57079632679489661923);   /* pi/2 */
    emit(-1.57079632679489661923);
    emit(0.78539816339744830962);   /* pi/4 */
    emit(-0.78539816339744830962);
    emit(2.71828182845904523536);   /* e */
    emit(-2.71828182845904523536);
    emit(0.69314718055994530942);   /* ln2 */
    emit(-0.69314718055994530942);
    emit(1.41421356237309504880);   /* sqrt(2) */
    emit(-1.41421356237309504880);

    /* --- Section 7: Powers of two (10) --- */
    emit(4.0);                      /* 2^2 */
    emit(-4.0);
    emit(1024.0);                   /* 2^10 */
    emit(-1024.0);
    emit_u(0x4130000000000000ULL);  /* 2^20 = 1048576.0 */
    emit_u(0xc130000000000000ULL);  /* -2^20 */
    emit_u(0x4330000000000000ULL);  /* 2^52 = 4503599627370496.0 */
    emit_u(0xc330000000000000ULL);  /* -2^52 */
    emit_u(0x4340000000000000ULL);  /* 2^53 = 9007199254740992.0 (mantissa boundary) */
    emit_u(0xc340000000000000ULL);  /* -2^53 */

    /* --- Section 8: Large magnitudes (8) --- */
    emit(1.0e10);
    emit(-1.0e10);
    emit(1.0e100);
    emit(-1.0e100);
    emit(1.0e200);
    emit(-1.0e200);
    emit(1.0e300);
    emit(-1.0e300);

    /* --- Section 9: Small normal values (8) --- */
    emit(1.0e-10);
    emit(-1.0e-10);
    emit(1.0e-50);
    emit(-1.0e-50);
    emit(1.0e-100);
    emit(-1.0e-100);
    emit(1.0e-200);
    emit(-1.0e-200);

    /* --- Section 10: Miscellaneous, sign-bit and ULP stress (27) --- */
    emit(0.1);
    emit(-0.1);
    emit(0.3);
    emit(-0.3);
    emit(1.5);
    emit(-1.5);
    emit(3.0);
    emit(-3.0);
    emit(5.0);
    emit(-5.0);
    emit(10.0);
    emit(-10.0);
    emit(100.0);
    emit(-100.0);
    emit(1000.0);
    emit(-1000.0);
    emit(1.0e15);
    emit(-1.0e15);
    emit(1.0e-300);
    emit(-1.0e-300);
    emit(0.125);                    /* 2^-3, exact in IEEE 754 */
    emit(-0.125);
    emit_u(0x3fbfffffffffffffULL);  /* one ULP below 0.125 */
    emit_u(0x3fc0000000000001ULL);  /* one ULP above 0.125 */
    emit_u(0x3ca0000000000000ULL);  /* 2^-52: smallest relative to 1.0 */
    emit_u(0xbca0000000000000ULL);  /* -2^-52 */
    emit(7.0);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf result: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
#endif
    return 0;
}

